/**
 * Regression tests for #1826 envelope-cleanup hook.
 *
 * The hook quarantines historical `{"continue":true,...}`-named entries
 * under ~/.claude/hooks/sessions/ and <projectDir>/.worktrees/, then writes
 * a done-marker so subsequent runs short-circuit.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, mkdirSync, writeFileSync, rmSync, existsSync, readdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  cleanupEnvelopeCorruption,
  __internals,
} from '../../lifecycle/cleanup-envelope-corruption.js';
import { NOOP_CTX } from '../../lib/context.js';

const ENVELOPE = '{"continue":true,"suppressOutput":true}';

describe('cleanupEnvelopeCorruption (#1826)', () => {
  let fakeHome: string;
  let fakeProject: string;
  let originalHome: string | undefined;
  let originalProject: string | undefined;

  beforeEach(() => {
    fakeHome = mkdtempSync(join(tmpdir(), 'envelope-cleanup-home-'));
    fakeProject = mkdtempSync(join(tmpdir(), 'envelope-cleanup-project-'));
    originalHome = process.env.HOME;
    originalProject = process.env.CLAUDE_PROJECT_DIR;
    process.env.HOME = fakeHome;
    process.env.CLAUDE_PROJECT_DIR = fakeProject;
  });

  afterEach(() => {
    if (originalHome === undefined) delete process.env.HOME;
    else process.env.HOME = originalHome;
    if (originalProject === undefined) delete process.env.CLAUDE_PROJECT_DIR;
    else process.env.CLAUDE_PROJECT_DIR = originalProject;
    rmSync(fakeHome, { recursive: true, force: true });
    rmSync(fakeProject, { recursive: true, force: true });
  });

  it('isCorrupt detects envelope substrings', () => {
    expect(__internals.isCorrupt(ENVELOPE)).toBe(true);
    expect(__internals.isCorrupt(`prefix-${ENVELOPE}-suffix`)).toBe(true);
    expect(__internals.isCorrupt('normal-session-id')).toBe(false);
    expect(__internals.isCorrupt('2026-03-09-17-summary.md')).toBe(false);
  });

  it('quarantines corrupt files under ~/.claude/hooks/sessions/', () => {
    const sessionsDir = join(fakeHome, '.claude', 'hooks', 'sessions');
    mkdirSync(sessionsDir, { recursive: true });
    writeFileSync(join(sessionsDir, `2026-03-09-17-${ENVELOPE}.md`), 'corrupt');
    writeFileSync(join(sessionsDir, '2026-03-09-17-clean.md'), 'clean');

    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);

    expect(readdirSync(sessionsDir)).toEqual(['2026-03-09-17-clean.md']);
    const qDir = __internals.quarantineDir();
    expect(existsSync(qDir)).toBe(true);
    expect(readdirSync(qDir).length).toBe(1);
  });

  it('quarantines corrupt worktree directories under <project>/.worktrees/', () => {
    const wtRoot = join(fakeProject, '.worktrees');
    mkdirSync(join(wtRoot, ENVELOPE), { recursive: true });
    mkdirSync(join(wtRoot, 'feature-clean'), { recursive: true });

    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);

    expect(readdirSync(wtRoot).sort()).toEqual(['feature-clean']);
  });

  it('writes the done-marker after a successful sweep', () => {
    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);
    const marker = join(fakeHome, '.claude', __internals.DONE_MARKER_FILENAME);
    expect(existsSync(marker)).toBe(true);
  });

  it('short-circuits on subsequent runs once the marker is present', () => {
    const sessionsDir = join(fakeHome, '.claude', 'hooks', 'sessions');
    mkdirSync(sessionsDir, { recursive: true });

    // First run — writes marker, no work.
    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);

    // Drop corruption AFTER the marker exists — second run must NOT touch it.
    writeFileSync(join(sessionsDir, `${ENVELOPE}.md`), 'should-stay');
    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);

    expect(existsSync(join(sessionsDir, `${ENVELOPE}.md`))).toBe(true);
  });

  it('quarantines a corrupt entry at the PROJECT ROOT (#1978)', () => {
    // The client-at-private.ai.remoteicu case: the envelope leaked to the repo
    // root, not under .worktrees. The original mitigation missed this.
    mkdirSync(join(fakeProject, ENVELOPE), { recursive: true });
    mkdirSync(join(fakeProject, 'app'), { recursive: true });
    writeFileSync(join(fakeProject, 'package.json'), '{}');

    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);

    expect(existsSync(join(fakeProject, ENVELOPE))).toBe(false);
    expect(existsSync(join(fakeProject, 'app'))).toBe(true);
    expect(existsSync(join(fakeProject, 'package.json'))).toBe(true);
  });

  it('catches a root-level recurrence even AFTER the done-marker exists (#1978)', () => {
    // First run writes the marker (idempotence for the slow sessions/ sweep).
    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);
    expect(existsSync(join(fakeHome, '.claude', __internals.DONE_MARKER_FILENAME))).toBe(true);

    // A NEW envelope leaks at the project root after the marker is set.
    mkdirSync(join(fakeProject, ENVELOPE), { recursive: true });

    // The root sweep is NOT marker-gated, so the second run still cleans it.
    cleanupEnvelopeCorruption({ hook_event: 'SessionStart' } as never, NOOP_CTX);
    expect(existsSync(join(fakeProject, ENVELOPE))).toBe(false);
  });

  it('returns silent success even when nothing is corrupt', () => {
    const result = cleanupEnvelopeCorruption(
      { hook_event: 'SessionStart' } as never,
      NOOP_CTX,
    );
    expect(result).toEqual({ continue: true, suppressOutput: true });
  });
});
